function NoMetadataQueryComponent({ utilities }) {
  const [data, setData] = useState([]);

  useEffect(() => {
    async function loadData() {
      const result = await utilities.rq.RunQuery({
        QueryName: 'NonExistentTestQuery12345',
        CategoryPath: 'Test/Reports'
      });
      if (result?.Success) {
        setData(result.Results);
      }
    }
    loadData();
  }, []);

  return (
    <div>
      <h3>Query Results</h3>
      {data.map((item, i) => (
        <div key={i}>{JSON.stringify(item)}</div>
      ))}
    </div>
  );
}
